const { ApolloServer, gql } = require('apollo-server-express');
const { createServer } = require('http');
const express = require('express');

const typeDefs = gql`
  type Invoice {
    id: ID!
    customerId: ID!
    amount: Float!
    status: String!
    createdAt: String!
    items: [InvoiceItem!]!
  }

  type InvoiceItem {
    id: ID!
    description: String!
    quantity: Int!
    price: Float!
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

const resolvers = {
  Query: {
    invoice: async (parent, args, context) => {
      const { id } = args;
      const { userId } = context;
      
      // Validate input
      if (!id || typeof id !== 'string') {
        throw new Error('Invalid invoice ID');
      }
      
      // Sanitize input to prevent injection attacks
      const sanitizedId = id.replace(/[^a-zA-Z0-9\-_]/g, '');
      
      // Check if user has access to this invoice
      const invoice = await getInvoiceById(sanitizedId);
      
      if (!invoice) {
        throw new Error('Invoice not found');
      }
      
      // Verify user ownership
      if (invoice.customerId !== userId) {
        throw new Error('Access denied');
      }
      
      return invoice;
    }
  }
};

// Mock database function
async function getInvoiceById(id) {
  // In a real implementation, this would query a database
  // with proper parameterized queries to prevent SQL injection
  return {
    id: id,
    customerId: 'customer-123',
    amount: 100.00,
    status: 'paid',
    createdAt: new Date().toISOString(),
    items: [
      {
        id: 'item-1',
        description: 'Service',
        quantity: 1,
        price: 100.00
      }
    ]
  };
}

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Authentication middleware should have already verified the user
    return {
      userId: req.user ? req.user.id : null
    };
  }
});

const app = express();
server.applyMiddleware({ app, path: '/graphql' });

const httpServer = createServer(app);
server.installSubscriptionHandlers(httpServer);

module.exports = { server, app, httpServer };